sql:
SELECT webhooks.id
FROM webhooks
WHERE webhooks.id IN (
    SELECT webhook_id
    FROM webhook_events
);

SELECT merchant_name 
FROM webhooks 
WHERE retry_limit > (SELECT AVG(retry_interval) FROM webhooks);

SELECT COUNT(DISTINCT account_id) 
FROM webhooks 
WHERE failure_count > 3;

SELECT MIN(merchant_name)
FROM webhooks
WHERE failure_count > 5;

external_knowledge:
- "treading through a stormy sea of consecutive failures" refers to WebHooks that have experienced failures without any success;
- "caught a breath of success" and "last saw clear skies" both refer to the last time a WebHook had a successful status;
- "hit rough waters" symbolizes the occurrence of a failure event.

sql:
SELECT id, webhook_id, event
FROM webhook_events
WHERE webhook_id = '0';

SELECT name 
FROM merchant_accounts
WHERE id = 0;

external_knowledge:
- An inactive webhook is defined as one that has not been triggered in more than 7 days;
- The term "most inactive webhooks" refers to the merchants with the highest count of such webhooks;
- The webhooks are considered enabled if their status is set to 1.

sql:
SELECT DISTINCT merchant_name
FROM webhooks
WHERE failure_count > 0;

SELECT event, COUNT(event) as event_count, MAX(created_at) as last_event_date
FROM webhook_events
GROUP BY event;
